import { TransformNode, ImportMeshAsync, Vector3 } from "babylonjs";
import "babylonjs-loaders";

export default class SplatLoaderScript {
    private _attachedNode: TransformNode;

    constructor(attachedNode: TransformNode) {
        this._attachedNode = attachedNode;
    }

    public async onStart(): Promise<void> {
        console.log(">>> Splat loader initialized.");
        
        // Using an optimized, compressed .splat asset from Babylon.js to prevent WebGL context loss
        const optimizedUrl = "https://assets.babylonjs.com/splats/gs_Skull.splat";
        const scene = this._attachedNode.getScene();

        try {
            console.log(">>> Downloading optimized splat asset...");
            const result = await ImportMeshAsync(optimizedUrl, scene);
            
            const splatMesh = result.meshes[0];
            if (splatMesh) {
                splatMesh.name = "Optimized_Splat_Mesh";
                
                // Bind the asset to your transform node hierarchy
                splatMesh.parent = this._attachedNode;
                
                // Explicitly spawn it at 0, 0, 2 relative to the parent transform node
                splatMesh.position = new Vector3(0, 0, 2);
                
                console.log(">>> Asset successfully spawned at relative coordinates (0, 0, 2).");
            }
        } catch (error) {
            console.error(">>> Runtime error during asset placement:", error);
        }
    }
}